-- Migration: add email to profiles + email-based profile recovery trigger
-- Allows existing users from the old Google OAuth project to recover their
-- profiles when signing in via email OTP on the new project.

-- ============================================================
-- 1. Add email column to profiles
-- ============================================================
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS email TEXT;

CREATE UNIQUE INDEX IF NOT EXISTS profiles_email_key
  ON public.profiles(email)
  WHERE email IS NOT NULL;

-- Populate email for any profiles already linked to a real auth.users
UPDATE public.profiles p
SET email = u.email
FROM auth.users u
WHERE p.user_id = u.id AND p.email IS NULL;

