-- ============================================================
-- 3. One-shot fix: recover dgouron56@gmail.com existing session
--    new auth UUID  : bb4ed93c-45e1-4c15-8355-f3720e6767b9
--    old profile    : 3003cda1-2999-419b-a7e8-94a63e307e51 ("Doran Gouron Le Roch", xp 2070)
--    empty profile  : 49b3cca8-ba95-4cfa-abac-6e46ed4142b3 (created today, xp 0)
-- ============================================================
DO $$
DECLARE
  new_uid UUID := 'bb4ed93c-45e1-4c15-8355-f3720e6767b9';
  old_uid UUID := '3003cda1-2999-419b-a7e8-94a63e307e51';
  empty_pid UUID := '49b3cca8-ba95-4cfa-abac-6e46ed4142b3';
BEGIN
  UPDATE public.performances          SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.user_follows          SET follower_id    = new_uid WHERE follower_id    = old_uid;
  UPDATE public.user_follows          SET following_id   = new_uid WHERE following_id   = old_uid;
  UPDATE public.bar_follows           SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.performance_yermats   SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.performance_comments  SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.notifications         SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.notifications         SET source_user_id = new_uid WHERE source_user_id = old_uid;
  UPDATE public.monthly_medals        SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.user_roles            SET user_id        = new_uid WHERE user_id        = old_uid;
  UPDATE public.profiles SET user_id = new_uid, email = 'dgouron56@gmail.com' WHERE user_id = old_uid;
  DELETE FROM public.profiles WHERE id = empty_pid;
END $$;

-- ============================================================
-- 4. Rewrite handle_new_user trigger: link orphaned profile by email
-- ============================================================
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
DECLARE
  base_username TEXT;
  final_username TEXT;
  counter       INTEGER := 0;
  old_profile   RECORD;
BEGIN
  -- Look for an orphaned profile (no matching auth.users) with this email
  SELECT p.id, p.user_id INTO old_profile
  FROM public.profiles p
  WHERE p.email = NEW.email
    AND NOT EXISTS (SELECT 1 FROM auth.users u WHERE u.id = p.user_id)
  LIMIT 1;

  IF old_profile.id IS NOT NULL THEN
    -- Re-link all tables to the new auth UUID
    UPDATE public.performances          SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.user_follows          SET follower_id    = NEW.id WHERE follower_id    = old_profile.user_id;
    UPDATE public.user_follows          SET following_id   = NEW.id WHERE following_id   = old_profile.user_id;
    UPDATE public.bar_follows           SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.performance_yermats   SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.performance_comments  SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.notifications         SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.notifications         SET source_user_id = NEW.id WHERE source_user_id = old_profile.user_id;
    UPDATE public.push_subscriptions    SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.user_roles            SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.monthly_medals        SET user_id        = NEW.id WHERE user_id        = old_profile.user_id;
    UPDATE public.profiles SET user_id = NEW.id, email = NEW.email WHERE id = old_profile.id;
    RETURN NEW;
  END IF;

  -- No orphaned profile → create a fresh one
  base_username := lower(regexp_replace(split_part(NEW.email, '@', 1), '[^a-z0-9_]', '', 'g'));
  IF length(base_username) < 3 THEN base_username := 'user' || base_username; END IF;
  final_username := base_username;
  WHILE EXISTS (SELECT 1 FROM public.profiles WHERE username = final_username) LOOP
    counter := counter + 1;
    final_username := base_username || counter::TEXT;
  END LOOP;

  INSERT INTO public.profiles (user_id, username, avatar_url, email)
  VALUES (NEW.id, final_username, NEW.raw_user_meta_data ->> 'avatar_url', NEW.email);
  RETURN NEW;
END;
$$;
